import{c as t,Q as a,j as o,m as r}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse(`{"title":"35 Claude Code Commands, Tricks, and Workflows That Most Users Don't Know — @eng_khairallah1","description":"","frontmatter":{"title":"35 Claude Code Commands, Tricks, and Workflows That Most Users Don't Know — @eng_khairallah1","author":"Khairallah AL-Awady（@eng_khairallah1）","date":"2026-04-21T00:00:00.000Z","source":"https://x.com/eng_khairallah1/status/2046519525907317043","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-21-@eng_khairallah1-317043.md","filePath":"research/tweets/2026-04-21-@eng_khairallah1-317043.md","lastUpdated":1779894392000}`),i={name:"research/tweets/2026-04-21-@eng_khairallah1-317043.md"};function n(l,e,s,h,d,c){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_35-claude-code-commands-tricks-and-workflows-that-most-users-don-t-know-—-eng-khairallah1" tabindex="-1">35 Claude Code Commands, Tricks, and Workflows That Most Users Don&#39;t Know — @eng_khairallah1 <a class="header-anchor" href="#_35-claude-code-commands-tricks-and-workflows-that-most-users-don-t-know-—-eng-khairallah1" aria-label="Permalink to &quot;35 Claude Code Commands, Tricks, and Workflows That Most Users Don&#39;t Know — @eng_khairallah1&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/eng_khairallah1/status/2046519525907317043" target="_blank" rel="noreferrer">https://x.com/eng_khairallah1/status/2046519525907317043</a><strong>作者</strong>：Khairallah AL-Awady（@eng_khairallah1） <strong>發布日期</strong>：2026-04-21 <strong>收錄日期</strong>：2026-04-26 <strong>類型</strong>：Twitter Article <strong>統計</strong>：1,593 likes · 244 retweets · 11,090 bookmarks · 5,000,423 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>I have been using Claude Code daily for months. These are the 35 techniques that make it feel like a cheat code.</p><h3 id="essential-commands-01-to-08" tabindex="-1">Essential Commands (01 to 08) <a class="header-anchor" href="#essential-commands-01-to-08" aria-label="Permalink to &quot;Essential Commands (01 to 08)&quot;">​</a></h3><ol><li><p><strong>Plan Mode (Shift + Tab)</strong>：切換到 Plan Mode 分析 codebase 並創建架構計劃，不寫任何代碼。先審閱計劃、批准後再切換回實作模式。「This single habit prevents more bugs than any other technique on this list.」</p></li><li><p><strong>/compact</strong>：30-45 分鐘後 context 膨脹，壓縮為關鍵決策和當前狀態的摘要</p></li><li><p><strong>/clear</strong>：開始新任務時清空，防止不同 feature 的 context 衝突</p></li><li><p><strong>/init</strong>：在新專案開始時運行，掃描 codebase 自動生成 CLAUDE.md（含結構、技術棧、編碼模式、架構決策）</p></li><li><p><strong>/cost</strong>：查看 session 的 token 用量。「Check this every hour during long sessions.」</p></li><li><p><strong>/memory</strong>：添加跨 session 持久的指令（「Always use TypeScript strict mode」「Always run tests after modifying any file in /src/core」）</p></li><li><p><strong>! prefix</strong>：用 ! 前綴直接執行 terminal 命令（不離開 Claude Code 界面運行測試/git 等）</p></li><li><p><strong>Multi-Model Switching</strong>：Opus 用於規劃和架構決策；Sonnet 用於實作執行。「Plan with the thinker. Build with the builder.」</p></li></ol><h3 id="productivity-techniques-09-to-18" tabindex="-1">Productivity Techniques (09 to 18) <a class="header-anchor" href="#productivity-techniques-09-to-18" aria-label="Permalink to &quot;Productivity Techniques (09 to 18)&quot;">​</a></h3><ol start="9"><li><p><strong>The Reference File Technique</strong>：「Look at how authentication is implemented in src/auth/login.ts. Implement password reset following the exact same patterns.」比口頭描述產生更一致的代碼。</p></li><li><p><strong>The Screenshot Debug</strong>：截圖貼上 (Ctrl+V) + 簡短描述比長篇文字描述更快更精確。</p></li><li><p><strong>The Test-First Workflow</strong>：先寫測試（覆蓋 normal/edge/error cases），再實作通過測試的函式。</p></li><li><p><strong>The Incremental Build</strong>：不要說「build the entire feature」，而是分步驟（schema → API → validation → frontend），每步測試，產出品質遠優於一次性 prompt。</p></li><li><p><strong>The Codebase Question</strong>：改動前先問「Read src/services/ and explain how data flows...」理解架構再建構，防止架構錯誤。</p></li><li><p><strong>The Diff Review</strong>：改動後要求「Show me a diff of every file you modified. Explain each change in one sentence.」捕捉非預期修改。</p></li><li><p><strong>The Error Paste</strong>：完整貼上錯誤信息（不是摘要），加上「Diagnose the root cause step by step before suggesting a fix.」</p></li><li><p><strong>The Undo Checkpoint</strong>：每次重大改動前 <code>git add . &amp;&amp; git commit -m &quot;checkpoint before [change]&quot;</code></p></li><li><p><strong>The Parallel Session</strong>：大型 feature 開兩個 terminal window，各自處理 backend 和 frontend，各自有乾淨 context。</p></li><li><p><strong>The Documentation Pass</strong>：功能完成後立即生成文件（此時最準確）</p></li></ol><h3 id="architecture-techniques-19-to-26" tabindex="-1">Architecture Techniques (19 to 26) <a class="header-anchor" href="#architecture-techniques-19-to-26" aria-label="Permalink to &quot;Architecture Techniques (19 to 26)&quot;">​</a></h3><ol start="19"><li><p><strong>The Pattern Extraction</strong>：讓 Claude Code 分析現有代碼模式，再用此分析指導新開發</p></li><li><p><strong>The Interface-First Design</strong>：先定義 interfaces 和 types，再實作</p></li><li><p><strong>The Error Boundary Mapping</strong>：識別所有可能失敗點，設計錯誤處理策略</p></li><li><p><strong>The Dependency Audit</strong>：在引入新 dependency 前讓 Claude 評估替代方案</p></li><li><p><strong>The Refactor Protocol</strong>：重構前先讓 Claude 寫充分的 tests，再執行重構</p></li><li><p><strong>The Migration Plan</strong>：大型遷移前讓 Claude 生成逐步計劃（帶 rollback 點）</p></li><li><p><strong>The Security Review</strong>：功能完成後要求安全審查（注入攻擊、認證問題、數據泄露）</p></li><li><p><strong>The Performance Audit</strong>：讓 Claude 分析 bottlenecks 並提供帶成本估算的修復建議</p></li></ol><h3 id="workflow-automation-27-to-31" tabindex="-1">Workflow Automation (27 to 31) <a class="header-anchor" href="#workflow-automation-27-to-31" aria-label="Permalink to &quot;Workflow Automation (27 to 31)&quot;">​</a></h3><p>27-31. Scripts that run automatically on triggers; Claude-generated make targets; CI/CD hooks; PR description generators; automated testing reporters</p><h3 id="debug-and-recovery-32-to-35" tabindex="-1">Debug and Recovery (32 to 35) <a class="header-anchor" href="#debug-and-recovery-32-to-35" aria-label="Permalink to &quot;Debug and Recovery (32 to 35)&quot;">​</a></h3><ol start="32"><li><p><strong>The Context Rebuild</strong>：Lost context 後快速重建—讓 Claude 讀取相關文件並摘要當前狀態</p></li><li><p><strong>The Regression Hunter</strong>：「What changed in the last 5 commits that could cause this bug?」</p></li><li><p><strong>The Clean Slate Debug</strong>：/clear 後重新陳述問題，排除 context 污染的影響</p></li><li><p><strong>The Step-by-Step Trace</strong>：「Walk through the code execution for this input step by step, predicting the output at each line.」</p></li></ol><h3 id="the-setup-that-ties-it-all-together" tabindex="-1">The Setup That Ties It All Together <a class="header-anchor" href="#the-setup-that-ties-it-all-together" aria-label="Permalink to &quot;The Setup That Ties It All Together&quot;">​</a></h3><p>強健的 CLAUDE.md + /memory 的 persistent rules + 一致的 Plan → Build → Test → Document 循環</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：35 個 Claude Code 實戰技巧，最高槓桿的是 Plan Mode (Shift+Tab)、Reference File Technique（指向現有代碼而非口頭描述）、Diff Review（捕捉非預期修改）和 Incremental Build 工作流。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li>Plan Mode + Incremental Build 組合是最高 bug 預防槓桿（先計劃後實作，每步測試）</li><li>Reference File Technique 替代口頭描述：讓 Claude 讀現有實作並複製模式，比描述更精確</li><li>Diff Review 是被低估的重要習慣：Claude 有時「善意地」修改你沒要求修改的文件</li><li>Multi-Model Switching（Opus 規劃 + Sonnet 執行）是成本與品質的最優平衡</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>作者每日使用 Claude Code 「數月」</li><li>Views：5,000,423（極高傳播）</li><li>Bookmarks：11,090（最高 bookmark 率的推文之一）</li><li>推薦使用頻率：/compact 每 30-45 分鐘，/cost 每小時</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li>35 個技巧中有部分（如 23-31）描述很淺，無操作細節</li><li>Reference File Technique 和 Diff Review 是較少被其他文章提到的高價值技巧</li><li>內容與 cc-workspace 現有規則（core.md、karpathy-principles.md）高度互補，但有一些工程師特有洞見</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>8/10</td><td>Reference File Technique 和 Diff Review 可直接補充到 cc-workspace 的實作規則</td></tr><tr><td>B. 創新性 (20%)</td><td>6/10</td><td>部分技巧（Diff Review、Parallel Session）在文章中較少提及</td></tr><tr><td>C. 證據品質 (20%)</td><td>6/10</td><td>每日實際使用驗證，5M views 表示社群廣泛認可</td></tr><tr><td>D. 技術深度 (15%)</td><td>6/10</td><td>多數技巧有具體操作說明，部分（27-31）過淺</td></tr><tr><td>E. 泛化性 (15%)</td><td>8/10</td><td>跨語言/框架/任務類型通用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>6.9/10</strong></td><td>8×0.3 + 6×0.2 + 6×0.2 + 6×0.15 + 8×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Skill <strong>理由</strong>：35 個技巧作為高質量的 Claude Code 操作 playbook，適合整合為 <code>claude-code-operations</code> SKILL，提供 cc-workspace 的開發工作流標準操作清單（補充 Plan→Build→Test→Document 循環和 Diff Review 等未在現有規則中記錄的習慣）</p>',30)])])}const p=t(i,[["render",n]]);export{g as __pageData,p as default};
